file_path = var_functions.query_db:16
with open(file_path, 'r') as f:
    all_businesses = json.load(f)

# Get businesses with reviews in 2018
businesses_with_reviews_2018 = locals()['var_functions.query_db:2']
business_refs_2018 = {b['business_ref'] for b in businesses_with_reviews_2018}

# Convert to business_id format
business_ids_2018 = {f"businessid_{bref.split('_')[1]}" for bref in business_refs_2018}

# Check which of these businesses have business_parking or bike_parking
eligible_businesses = []
for record in all_businesses:
    if record['business_id'] in business_ids_2018:
        # Check if this business has parking attributes
        if record.get('attributes'):
            # Check for BusinessParking or BikeParking
            if isinstance(record.get('attributes'), dict):
                business_parking = record['attributes'].get('BusinessParking')
                bike_parking = record['attributes'].get('BikeParking')

                # Check if business_parking exists and is not None or 'None'
                has_business_parking = business_parking and str(business_parking) != 'None' and str(business_parking) != ''

                # Check if bike_parking exists and has value
                has_bike_parking = bike_parking and str(bike_parking) != ''

                if has_business_parking or has_bike_parking:
                    eligible_businesses.append({
                        'business_id': record['business_id'],
                        'business_parking': business_parking,
                        'bike_parking': bike_parking
                    })

print('__RESULT__:')
print(json.dumps({
    'total_businesses_with_reviews_2018': len(business_ids_2018),
    'eligible_businesses': eligible_businesses,
    'eligible_count': len(eligible_businesses)
}))"}

